import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { transformToFinancialProduct, CATEGORY_LABEL } from '../utils/finance';
import ProductCard from '../components/ProductCard';
import { RiskBadge, ReturnDisplay } from '../components/Badges';
import { useUserProfile } from '../contexts/UserProfileContext';
import './Home.css';

const CATEGORIES = [
  { key: 'savings',    icon: '🏦', label: 'Savings',    desc: 'Low risk, stable growth' },
  { key: 'investment', icon: '📈', label: 'Investment', desc: 'Balanced risk & reward' },
  { key: 'insurance',  icon: '🛡️', label: 'Insurance',  desc: 'Protect your assets' },
  { key: 'crypto',     icon: '₿',  label: 'Crypto',     desc: 'High risk, high reward' },
];

export default function Home() {
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats]     = useState({ total: 0, categories: 4, avgReturn: 0 });
  const { isProfileComplete } = useUserProfile();
  const navigate = useNavigate();

  useEffect(() => {
    fetch('https://fakestoreapi.com/products')
      .then(r => r.json())
      .then(data => {
        const all = data.map(transformToFinancialProduct);
        // Featured: pick best return from each category (dynamic selection)
        const cats = ['savings', 'investment', 'insurance', 'crypto'];
        const featured = cats.map(cat => {
          const inCat = all.filter(p => p.category === cat);
          return inCat.sort((a, b) => b.expectedReturn - a.expectedReturn)[0];
        }).filter(Boolean);

        const avgReturn = parseFloat(
          (all.reduce((s, p) => s + p.expectedReturn, 0) / all.length).toFixed(1)
        );

        setFeaturedProducts(featured);
        setStats({ total: all.length, categories: 4, avgReturn });
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  return (
    <div className="page page-enter">
      {/* Hero */}
      <section className="hero">
        <div className="hero-bg" />
        <div className="container hero-inner">
          <div className="hero-tag badge">✦ Smart Investing Platform</div>
          <h1 className="hero-title">
            Discover <span>Financial</span><br />Products Built For You
          </h1>
          <p className="hero-sub">
            Explore savings, investments, insurance, and crypto assets —
            filtered and recommended based on your personal risk profile and goals.
          </p>
          <div className="hero-cta">
            <Link to="/products" className="btn btn-primary">
              Explore Products →
            </Link>
            <Link to="/profile" className="btn btn-outline">
              {isProfileComplete() ? 'Update Profile' : 'Create Profile'}
            </Link>
          </div>

          {/* Quick Stats */}
          <div className="hero-stats">
            {[
              { label: 'Products', value: stats.total || '20+' },
              { label: 'Categories', value: stats.categories },
              { label: 'Avg Return', value: `${stats.avgReturn}%` },
              { label: 'Risk Levels', value: '3' },
            ].map(s => (
              <div key={s.label} className="hero-stat">
                <span className="hero-stat-val">{s.value}</span>
                <span className="hero-stat-label">{s.label}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Category Nav */}
      <section className="home-section container">
        <div className="section-header">
          <div>
            <h2 className="section-title">Browse by <span>Category</span></h2>
            <p className="section-subtitle">Click to filter products by type</p>
          </div>
        </div>
        <div className="category-grid">
          {CATEGORIES.map(cat => (
            <button
              key={cat.key}
              className="cat-card"
              onClick={() => navigate(`/products?category=${cat.key}`)}
            >
              <span className="cat-icon">{cat.icon}</span>
              <span className="cat-label">{cat.label}</span>
              <span className="cat-desc">{cat.desc}</span>
              <span className="cat-arrow">→</span>
            </button>
          ))}
        </div>
      </section>

      {/* Featured Products */}
      <section className="home-section container">
        <div className="section-header">
          <div>
            <h2 className="section-title">Featured <span>Products</span></h2>
            <p className="section-subtitle">Top-return product from each category</p>
          </div>
          <Link to="/products" className="btn btn-outline btn-sm">View All</Link>
        </div>

        {loading ? (
          <div className="loading-wrap"><div className="spinner" /><p>Loading products…</p></div>
        ) : (
          <div className="products-grid">
            {featuredProducts.map(p => <ProductCard key={p.id} product={p} />)}
          </div>
        )}
      </section>

      {/* CTA Banner */}
      {!isProfileComplete() && (
        <section className="home-section container">
          <div className="cta-banner">
            <div>
              <h3 className="cta-title">Get Personalized Recommendations</h3>
              <p className="cta-sub">Create your financial profile and let our engine match products to your goals.</p>
            </div>
            <Link to="/profile" className="btn btn-primary">Create Profile →</Link>
          </div>
        </section>
      )}
    </div>
  );
}
